import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import styles from "./DashboardPage.module.css";
import { MainLayout } from "../../layouts";
import { useLanguage } from "../../translet/LanguageContext";
import { useAuth } from "../../contexts/AuthContext";
import { ROUTES } from "../../constants";

export default function SavedJobsPage() {
  const { t } = useLanguage();
  const navigate = useNavigate();
  const { isAuthenticated, loading: authLoading } = useAuth();

  // State
  const [savedJobs, setSavedJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [unsavingJobId, setUnsavingJobId] = useState(null);

  // Pagination
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalJobs, setTotalJobs] = useState(0);
  const limit = 12;

  // Notification
  const [notification, setNotification] = useState({
    show: false,
    message: "",
    type: "success",
  });

  // Redirect to login if not authenticated
  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      navigate(ROUTES.LOGIN);
    }
  }, [isAuthenticated, authLoading, navigate]);

  // Fetch saved jobs
  useEffect(() => {
    if (isAuthenticated) {
      fetchSavedJobs();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page, isAuthenticated]);

  async function fetchSavedJobs() {
    try {
      setLoading(true);
      setError(null);

      const token = localStorage.getItem("authToken");
      const params = new URLSearchParams({
        page: page.toString(),
        limit: limit.toString(),
      });

      const response = await fetch(`/api/jobs/saved/list?${params.toString()}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();

      if (data.success) {
        setSavedJobs(data.data.savedJobs || []);
        setTotalPages(data.data.pagination?.totalPages || 1);
        setTotalJobs(data.data.pagination?.total || 0);
      }
    } catch (err) {
      console.error("Error fetching saved jobs:", err);
      setError(err.message);
      showNotification("Error loading saved jobs", "error");
    } finally {
      setLoading(false);
    }
  }

  async function handleUnsaveJob(jobId, event) {
    if (event) {
      event.stopPropagation();
    }

    if (unsavingJobId === jobId) return;

    try {
      setUnsavingJobId(jobId);

      const token = localStorage.getItem("authToken");
      const response = await fetch(`/api/jobs/${jobId}/save`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
      });

      const data = await response.json();

      if (data.success && !data.isSaved) {
        // Remove from list
        setSavedJobs((prev) => prev.filter((sj) => sj.jobId !== jobId));
        setTotalJobs((prev) => prev - 1);
        showNotification("Job removed from saved list", "success");
      } else {
        showNotification(data.message || "Failed to unsave job", "error");
      }
    } catch (error) {
      console.error("Error unsaving job:", error);
      showNotification("An error occurred", "error");
    } finally {
      setUnsavingJobId(null);
    }
  }

  function showNotification(message, type = "success") {
    setNotification({ show: true, message, type });
    setTimeout(() => {
      setNotification((prev) => ({ ...prev, show: false }));
    }, 3000);
  }

  function formatDate(dateString) {
    const date = new Date(dateString);
    return date.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  }

  function formatSalary(job) {
    if (job.salaryType === "NEGOTIABLE") return "Negotiable";
    if (job.minSalary && job.maxSalary) {
      return `$${job.minSalary} - $${job.maxSalary}`;
    }
    if (job.minSalary) return `From $${job.minSalary}`;
    return "Contact for details";
  }

  if (authLoading || !isAuthenticated) {
    return (
      <MainLayout>
        <div style={{ padding: "40px", textAlign: "center" }}>Loading...</div>
      </MainLayout>
    );
  }

  return (
    <MainLayout>
      {/* Notification */}
      {notification.show && (
        <div
          style={{
            position: "fixed",
            top: "20px",
            right: "20px",
            padding: "16px 24px",
            borderRadius: "12px",
            background:
              notification.type === "success"
                ? "linear-gradient(135deg, #10b981, #059669)"
                : "linear-gradient(135deg, #ef4444, #dc2626)",
            color: "white",
            fontWeight: "500",
            boxShadow: "0 8px 24px rgba(0, 0, 0, 0.15)",
            zIndex: 9999,
            animation: "slideIn 0.3s ease",
          }}
        >
          {notification.message}
        </div>
      )}

      <div className={styles.dashboardRoot}>
        {/* Sidebar */}
        <aside className={styles.sidebar}>
          <div className={styles.sidebarHeader}>
            <h2 className={styles.sidebarTitle}>{t("dashboard.pageTitle")}</h2>
          </div>
          <nav className={styles.sidebarNav}>
            <button
              className={styles.menuItem}
              onClick={() => navigate(ROUTES.DASHBOARD)}
            >
              <span className={styles.menuIcon}>📊</span>
              <span className={styles.menuLabel}>
                {t("dashboard.navigation.overview")}
              </span>
            </button>
            <button
              className={styles.menuItem}
              onClick={() => navigate(ROUTES.MY_APPLICATIONS)}
            >
              <span className={styles.menuIcon}>📋</span>
              <span className={styles.menuLabel}>
                {t("dashboard.navigation.applications")}
              </span>
            </button>
            <button
              className={`${styles.menuItem} ${styles.menuItemActive}`}
              onClick={() => navigate(ROUTES.SAVED_JOBS)}
            >
              <span className={styles.menuIcon}>❤️</span>
              <span className={styles.menuLabel}>
                {t("dashboard.navigation.favorites")}
              </span>
            </button>
            <button
              className={styles.menuItem}
              onClick={() => navigate(ROUTES.JOB_ALERTS)}
            >
              <span className={styles.menuIcon}>🔔</span>
              <span className={styles.menuLabel}>
                {t("dashboard.navigation.alerts")}
              </span>
            </button>
            <button
              className={styles.menuItem}
              onClick={() => navigate(ROUTES.PROFILE)}
            >
              <span className={styles.menuIcon}>👤</span>
              <span className={styles.menuLabel}>
                {t("dashboard.navigation.profile")}
              </span>
            </button>
          </nav>
        </aside>

        {/* Main Content */}
        <main className={styles.mainContent}>
          {/* Header */}
          <header className={styles.contentHeader}>
            <h1 className={styles.greeting}>Saved Jobs</h1>
            <p className={styles.subGreeting}>
              {totalJobs} {totalJobs === 1 ? "job" : "jobs"} saved
            </p>
          </header>

          {/* Content */}
          {loading && (
            <div style={{ textAlign: "center", padding: "40px", fontSize: "18px" }}>
              Loading saved jobs...
            </div>
          )}

          {error && (
            <div
              style={{
                textAlign: "center",
                padding: "40px",
                fontSize: "18px",
                color: "#ef4444",
              }}
            >
              {error}
            </div>
          )}

          {!loading && !error && savedJobs.length === 0 && (
            <div style={{ textAlign: "center", padding: "60px 24px" }}>
              <div style={{ fontSize: "4rem", marginBottom: "20px" }}>❤️</div>
              <h2 style={{ fontSize: "1.5rem", marginBottom: "12px" }}>
                No saved jobs yet
              </h2>
              <p style={{ color: "#64748b", marginBottom: "24px" }}>
                Start saving jobs you're interested in to view them here
              </p>
              <button
                onClick={() => navigate(ROUTES.FIND_JOB)}
                style={{
                  background: "linear-gradient(135deg, #0369a1, #0ea5e9)",
                  color: "white",
                  border: "none",
                  padding: "12px 28px",
                  borderRadius: "10px",
                  cursor: "pointer",
                  fontSize: "1rem",
                  fontWeight: "600",
                }}
              >
                Browse Jobs
              </button>
            </div>
          )}

          {!loading && !error && savedJobs.length > 0 && (
            <>
              <div className={styles.jobsList}>
                {savedJobs.map((savedJob) => {
                  const job = savedJob.job;
                  return (
                    <div key={savedJob.id} className={styles.jobCard}>
                      {/* Job Info */}
                      <div className={styles.jobInfo}>
                        <div className={styles.jobHeader}>
                          <div className={styles.companyLogo}>
                            {job.organization?.logo ? (
                              <img
                                src={job.organization.logo}
                                alt={job.organization.name}
                                style={{
                                  width: "100%",
                                  height: "100%",
                                  objectFit: "cover",
                                  borderRadius: "8px",
                                }}
                              />
                            ) : (
                              job.organization?.name?.[0] || "?"
                            )}
                          </div>
                          <div className={styles.jobDetails}>
                            <h3 className={styles.jobTitle}>{job.title}</h3>
                            <p className={styles.companyName}>
                              {job.organization?.name}
                            </p>
                            <div className={styles.jobTags}>
                              <span className={styles.tag}>
                                {job.workingMode?.name || "On-site"}
                              </span>
                              <span className={styles.tag}>
                                {job.quantity} position{job.quantity > 1 ? "s" : ""}
                              </span>
                            </div>
                            <div className={styles.jobMeta}>
                              <span className={styles.location}>
                                📍 {job.province}
                              </span>
                              <span className={styles.salary}>
                                💰 {formatSalary(job)}
                              </span>
                            </div>
                          </div>
                        </div>
                      </div>

                      {/* Saved Date */}
                      <div className={styles.dateColumn}>
                        <span className={styles.dateLabel}>Saved on</span>
                        <span className={styles.dateValue}>
                          {formatDate(savedJob.savedDate)}
                        </span>
                      </div>

                      {/* Actions */}
                      <div className={styles.actionColumn}>
                        <button
                          className={styles.viewDetailsBtn}
                          onClick={() => navigate(`${ROUTES.FIND_JOB}?jobId=${job.id}`)}
                        >
                          View Details
                        </button>
                        <button
                          onClick={(e) => handleUnsaveJob(job.id, e)}
                          disabled={unsavingJobId === job.id}
                          style={{
                            background: "transparent",
                            border: "2px solid #ef4444",
                            color: "#ef4444",
                            padding: "8px 16px",
                            borderRadius: "8px",
                            cursor: "pointer",
                            fontSize: "0.85rem",
                            fontWeight: "600",
                            marginTop: "8px",
                            width: "100%",
                            transition: "0.2s ease",
                          }}
                          onMouseEnter={(e) => {
                            e.target.style.background = "#ef4444";
                            e.target.style.color = "white";
                          }}
                          onMouseLeave={(e) => {
                            e.target.style.background = "transparent";
                            e.target.style.color = "#ef4444";
                          }}
                        >
                          {unsavingJobId === job.id ? "Removing..." : "Remove"}
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Pagination */}
              {totalPages > 1 && (
                <div
                  style={{
                    display: "flex",
                    justifyContent: "center",
                    gap: "8px",
                    marginTop: "40px",
                  }}
                >
                  {Array.from({ length: totalPages }).map((_, i) => {
                    const p = i + 1;
                    return (
                      <button
                        key={p}
                        onClick={() => setPage(p)}
                        style={{
                          minWidth: "40px",
                          height: "40px",
                          borderRadius: "8px",
                          border: "2px solid #e2e8f0",
                          background: page === p ? "#0369a1" : "white",
                          color: page === p ? "white" : "#1e293b",
                          cursor: "pointer",
                          fontWeight: "600",
                        }}
                      >
                        {p}
                      </button>
                    );
                  })}
                </div>
              )}
            </>
          )}
        </main>
      </div>
    </MainLayout>
  );
}
